async function buildPayload(calc,rows,summary){return{...STUDY,instrumentVersion:TESTS[activeTest].version,responseId:crypto.randomUUID(),sessionId,deviceRespondentId:deviceId,retestTokenHash:await hash(val('#retestToken')),randomization:{seed:deviceId,itemOrder:calc.responses.map(r=>r.itemId)},timing:{startedAt:new Date(startedAt).toISOString(),completedAt:new Date().toISOString(),totalDurationMs:Date.now()-startedAt},metadata:{language:currentLang,ageBand:val('#ageBand'),priorTypologyExposure:val('#exposure'),selfReportedType:val('#selfType'),viewport:{w:innerWidth,h:innerHeight},timezone:Intl.DateTimeFormat().resolvedOptions().timeZone},responses:calc.responses,scaleScores:Object.fromEntries(rows),resultSummary:summary,qualityFlags:{failedAttentionCheck:calc.failedAttention,straightlining:new Set(calc.responses.filter(r=>!r.attentionExpected).map(r=>r.responseValue)).size===1,tooFast:(Date.now()-startedAt)<45000}}}
