function gameIcon(kind,v){const icons={backpack:['×','?','🎒','✅','⭐'],mine:['○','·','⚠','💥','🧯'],bridge:['—','▱','▰','▰▰','🌉'],compass:['↙','↘','●','↗','↑'],phrase:['⌫','↙','□','＿','📌'],attention:['1','2','3','4','5']};return(icons[kind]||icons.backpack)[v-1]}
