function enhanceControlsA11y(){document.querySelectorAll('[data-lang]').forEach(b=>b.setAttribute('aria-pressed',String(b.dataset.lang===currentLang)));document.querySelectorAll('[data-test-key]').forEach(b=>b.setAttribute('aria-pressed',String(b.dataset.testKey===activeTest)));document.querySelectorAll('button:not([type])').forEach(b=>b.setAttribute('type','button'))}const a11yObserver=new MutationObserver(enhanceControlsA11y);a11yObserver.observe(document.body,{childList:true,subtree:true});document.querySelectorAll('[data-lang]').forEach(b=>b.onclick=()=>applyLanguage(b.dataset.lang));applyLanguage(currentLang);enhanceControlsA11y();
